const ctx = canvas.getContext('2d');

// ============================================================
// SPEED HACK PREVENTION SYSTEM
// ============================================================
// Instead of trusting client-reported delta times, we use
// server-authoritative timing with multiple validation layers.

class AntiSpeedHack {
    constructor() {
        // Use a server-side clock reference (simulated here)
        // In production, this would be the actual server timestamp
        this.serverTimeOrigin = performance.now();
        this.wallClockOrigin = Date.now();

        // Maximum allowed delta time (caps large deltas to prevent teleporting)
        this.MAX_DELTA_MS = 50; // Cap at 50ms (20 FPS minimum)

        // Minimum allowed delta time (prevents micro-stepping exploits)
        this.MIN_DELTA_MS = 8; // ~120 FPS max

        // Track timing anomalies
        this.anomalyCount = 0;
        this.MAX_ANOMALIES = 10;
        this.anomalyWindow = [];
        this.ANOMALY_WINDOW_MS = 5000;

        // Wall clock drift detection
        this.lastPerformanceNow = performance.now();
        this.lastDateNow = Date.now();
        this.maxClockDrift = 50; // ms tolerance between clocks

        // Accumulated time tracking to detect speed manipulation
        this.totalGameTime = 0;
        this.gameStartWallClock = Date.now();
        this.gameStartPerformance = performance.now();

        // Frame rate monitoring
        this.frameTimes = [];
        this.FRAME_HISTORY_SIZE = 60;

        // Distance/velocity sanity checks
        this.maxPlayerSpeed = 250; // pixels per second - absolute maximum
        this.positionHistory = [];
        this.POSITION_HISTORY_SIZE = 30;

        this.violations = [];
        this.isBanned = false;
    }

    // Get a validated, safe delta time - NEVER trust raw client deltas
    getValidatedDelta() {
        const now = performance.now();
        const wallNow = Date.now();

        // === Layer 1: Use OUR measured delta, not client-reported ===
        const rawDelta = now - this.lastPerformanceNow;

        // === Layer 2: Cross-reference with wall clock ===
        const wallDelta = wallNow - this.lastDateNow;
        const clockDrift = Math.abs(rawDelta - wallDelta);

        if (clockDrift > this.maxClockDrift) {
            this.recordAnomaly('CLOCK_DRIFT', `performance vs Date drift: ${clockDrift.toFixed(1)}ms`);
        }

        // === Layer 3: Clamp delta to sane range ===
        let safeDelta = Math.min(rawDelta, this.MAX_DELTA_MS);
        safeDelta = Math.max(safeDelta, this.MIN_DELTA_MS);

        // === Layer 4: Detect accumulated time manipulation ===
        this.totalGameTime += safeDelta;
        const expectedElapsed = performance.now() - this.gameStartPerformance;
        const timeRatio = this.totalGameTime / Math.max(expectedElapsed, 1);

        // If game time is running significantly faster than real time
        if (expectedElapsed > 1000 && timeRatio > 1.1) {
            this.recordAnomaly('TIME_ACCEL', `Time ratio: ${timeRatio.toFixed(3)}`);
            // Correct by reducing delta
            safeDelta *= 0.5;
        }

        // === Layer 5: Wall clock elapsed sanity check ===
        const wallElapsed = wallNow - this.gameStartWallClock;
        const perfElapsed = now - this.gameStartPerformance;
        if (wallElapsed > 2000) {
            const globalDrift = Math.abs(wallElapsed - perfElapsed);
            if (globalDrift > 500) {
                this.recordAnomaly('GLOBAL_DRIFT', `Wall vs Perf drift: ${globalDrift.toFixed(0)}ms`);
            }
        }

        // === Layer 6: Frame rate anomaly detection ===
        this.frameTimes.push(rawDelta);
        if (this.frameTimes.length > this.FRAME_HISTORY_SIZE) {
            this.frameTimes.shift();
        }
        if (this.frameTimes.length >= 10) {
            const avgFrame = this.frameTimes.reduce((a, b) => a + b, 0) / this.frameTimes.length;
            // If average frame time is suspiciously low (game running too fast)
            if (avgFrame < 5) {
                this.recordAnomaly('FRAME_SPEED', `Avg frame: ${avgFrame.toFixed(1)}ms`);
                safeDelta = 16.67; // Force to ~60fps
            }
        }

        this.lastPerformanceNow = now;
        this.lastDateNow = wallNow;

        return safeDelta / 1000; // Return in seconds
    }

    // Validate player position changes
    validateMovement(player, dx, dy, deltaSec) {
        if (this.isBanned) return { x: 0, y: 0 };

        const requestedSpeed = Math.sqrt(dx * dx + dy * dy) / Math.max(deltaSec, 0.001);

        // === Position-based speed check ===
        if (requestedSpeed > this.maxPlayerSpeed * 1.5) {
            this.recordAnomaly('SPEED_EXCEED', `Speed: ${requestedSpeed.toFixed(0)} px/s`);
            // Normalize to max speed
            const scale = this.maxPlayerSpeed / requestedSpeed;
            dx *= scale;
            dy *= scale;
        }

        // === Position history check ===
        this.positionHistory.push({
            x: player.x,
            y: player.y,
            time: performance.now()
        });
        if (this.positionHistory.length > this.POSITION_HISTORY_SIZE) {
            this.positionHistory.shift();
        }

        // Check distance over last N frames
        if (this.positionHistory.length >= 10) {
            const oldest = this.positionHistory[0];
            const newest = this.positionHistory[this.positionHistory.length - 1];
            const dist = Math.sqrt(
                Math.pow(newest.x - oldest.x, 2) +
                Math.pow(newest.y - oldest.y, 2)
            );
            const elapsed = (newest.time - oldest.time) / 1000;
            const avgSpeed = dist / Math.max(elapsed, 0.001);

            if (avgSpeed > this.maxPlayerSpeed * 1.3 && elapsed > 0.1) {
                this.recordAnomaly('AVG_SPEED', `Avg speed over ${elapsed.toFixed(2)}s: ${avgSpeed.toFixed(0)} px/s`);
                dx *= 0.5;
                dy *= 0.5;
            }
        }

        return { x: dx, y: dy };
    }

    recordAnomaly(type, detail) {
        const now = performance.now();

        // Clean old anomalies outside window
        this.anomalyWindow = this.anomalyWindow.filter(
            a => now - a.time < this.ANOMALY_WINDOW_MS
        );

        this.anomalyWindow.push({ type, detail, time: now });
        this.anomalyCount++;

        this.violations.push({
            type,
            detail,
            timestamp: new Date().toISOString()
        });

        // Keep violations list manageable
        if (this.violations.length > 100) {
            this.violations = this.violations.slice(-50);
        }

        console.warn(`[ANTI-CHEAT] ${type}: ${detail} (${this.anomalyWindow.length} anomalies in window)`);

        // Ban if too many anomalies in short window
        if (this.anomalyWindow.length >= this.MAX_ANOMALIES) {
            this.isBanned = true;
            console.error('[ANTI-CHEAT] Player banned for speed hacking!');
        }
    }

    getStatus() {
        const now = performance.now();
        const recentAnomalies = this.anomalyWindow.filter(
            a => now - a.time < this.ANOMALY_WINDOW_MS
        ).length;

        return {
            anomalies: recentAnomalies,
            totalViolations: this.violations.length,
            isBanned: this.isBanned,
            recentViolations: this.violations.slice(-3)
        };
    }
}

// ============================================================
// GAME STATE
// ============================================================

const antiCheat = new AntiSpeedHack();

const TRACK_LENGTH = 5000;
const PLAYER_SPEED = 200; // pixels per second

const player = {
    x: 50,
    y: 300,
    width: 30,
    height: 20,
    color: '#e94560',
    speed: PLAYER_SPEED,
    distanceTraveled: 0,
    finished: false,
    finishTime: null
};

const track = {
    offset: 0,
    checkpoints: [1000, 2000, 3000, 4000],
    checkpointsPassed: [],
    finishLine: TRACK_LENGTH
};

// Obstacles
const obstacles = [];
for (let i = 0; i < 30; i++) {
    obstacles.push({
        x: 300 + Math.random() * (TRACK_LENGTH - 400),
        y: 50 + Math.random() * 500,
        width: 20 + Math.random() * 40,
        height: 20 + Math.random() * 40,
        color: `hsl(${Math.random() * 60 + 180}, 70%, 40%)`
    });
}

// Boost pads (visual only, no speed increase - prevents confusion with hacks)
const boostPads = [];
for (let i = 0; i < 8; i++) {
    boostPads.push({
        x: 500 + Math.random() * (TRACK_LENGTH - 600),
        y: 100 + Math.random() * 400,
        width: 60,
        height: 30
    });
}

const keys = {};
let gameStartTime = null;
let gameRunning = true;

// Input handling
document.addEventListener('keydown', (e) => {
    keys[e.key.toLowerCase()] = true;
});
document.addEventListener('keyup', (e) => {
    keys[e.key.toLowerCase()] = false;
});

// ============================================================
// GAME LOOP - Uses validated delta times
// ============================================================

function update() {
    if (!gameRunning || player.finished || antiCheat.isBanned) return;

    if (!gameStartTime) gameStartTime = performance.now();

    // === KEY: Get validated delta from anti-cheat system ===
    // This does NOT trust any client-reported delta.
    // It measures its own delta and validates it against multiple clocks.
    const deltaSec = antiCheat.getValidatedDelta();

    // Calculate desired movement
    let dx = 0;
    let dy = 0;

    if (keys['w'] || keys['arrowup']) dy -= player.speed * deltaSec;
    if (keys['s'] || keys['arrowdown']) dy += player.speed * deltaSec;
    if (keys['a'] || keys['arrowleft']) dx -= player.speed * deltaSec;
    if (keys['d'] || keys['arrowright']) dx += player.speed * deltaSec;

    // Diagonal normalization
    if (dx !== 0 && dy !== 0) {
        const norm = 1 / Math.sqrt(2);
        dx *= norm;
        dy *= norm;
    }

    // === Validate movement through anti-cheat ===
    const validated = antiCheat.validateMovement(player, dx, dy, deltaSec);
    dx = validated.x;
    dy = validated.y;

    // Apply movement
    player.x += dx;
    player.y += dy;

    // Track distance (only forward movement counts)
    if (dx > 0) {
        player.distanceTraveled += dx;
    }

    // Boundary checks
    player.y = Math.max(10, Math.min(canvas.height - player.height - 10, player.y));
    player.x = Math.max(10, player.x);

    // Collision with obstacles
    for (const obs of obstacles) {
        const screenObsX = obs.x - track.offset;
        if (
            player.x < screenObsX + obs.width &&
            player.x + player.width > screenObsX &&
            player.y < obs.y + obs.height &&
            player.y + player.height > obs.y
        ) {
            // Push player back
            player.x -= dx * 2;
            player.y -= dy * 2;
            player.x = Math.max(10, player.x);
        }
    }

    // Camera follow
    track.offset = Math.max(0, player.x - 100);
    // Keep player on screen
    if (player.x - track.offset > canvas.width - 100) {
        track.offset = player.x - canvas.width + 100;
    }

    // Checkpoint tracking
    for (const cp of track.checkpoints) {
        if (player.distanceTraveled >= cp && !track.checkpointsPassed.includes(cp)) {
            track.checkpointsPassed.push(cp);
            console.log(`Checkpoint ${cp} reached!`);
        }
    }

    // Finish line check
    if (player.distanceTraveled >= track.finishLine) {
        player.finished = true;
        player.finishTime = ((performance.now() - gameStartTime) / 1000).toFixed(2);
    }
}

function render() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // Draw track background
    ctx.fillStyle = '#16213e';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Draw track lines
    ctx.strokeStyle = '#333';
    ctx.lineWidth = 1;
    for (let y = 0; y < canvas.height; y += 50) {
        ctx.beginPath();
        ctx.moveTo(0, y);
        ctx.lineTo(canvas.width, y);
        ctx.stroke();
    }

    // Draw grid (scrolling)
    ctx.strokeStyle = '#1a1a3e';
    for (let x = -track.offset % 100; x < canvas.width; x += 100) {
        ctx.beginPath();
        ctx.moveTo(x, 0);
        ctx.lineTo(x, canvas.height);
        ctx.stroke();
    }

    // Draw boost pads
    for (const bp of boostPads) {
        const screenX = bp.x - track.offset;
        if (screenX > -bp.width && screenX < canvas.width + bp.width) {
            ctx.fillStyle = 'rgba(255, 255, 0, 0.2)';
            ctx.fillRect(screenX, bp.y, bp.width, bp.height);
            ctx.strokeStyle = '#ff0';
            ctx.strokeRect(screenX, bp.y, bp.width, bp.height);
            // Chevrons
            ctx.fillStyle = '#ff0';
            ctx.font = '16px monospace';
            ctx.fillText('>>>', screenX + 5, bp.y + 20);
        }
    }

    // Draw obstacles
    for (const obs of obstacles) {
        const screenX = obs.x - track.offset;
        if (screenX > -obs.width && screenX < canvas.width + obs.width) {
            ctx.fillStyle = obs.color;
            ctx.fillRect(screenX, obs.y, obs.width, obs.height);
            ctx.strokeStyle = '#fff';
            ctx.lineWidth = 1;
            ctx.strokeRect(screenX, obs.y, obs.width, obs.height);
        }
    }

    // Draw checkpoints
    for (const cp of track.checkpoints) {
        const screenX = cp - track.offset;
        if (screenX > -10 && screenX < canvas.width + 10) {
            const passed = track.checkpointsPassed.includes(cp);
            ctx.strokeStyle = passed ? '#0f0' : '#ff0';
            ctx.lineWidth = 3;
            ctx.setLineDash([10, 5]);
            ctx.beginPath();
            ctx.moveTo(screenX, 0);
            ctx.lineTo(screenX, canvas.height);
            ctx.stroke();
            ctx.setLineDash([]);

            ctx.fillStyle = passed ? '#0f0' : '#ff0';
            ctx.font = '12px monospace';
            ctx.fillText(`CP ${cp}m`, screenX + 5, 20);
        }
    }

    // Draw finish line
    const finishScreenX = track.finishLine - track.offset;
    if (finishScreenX > -20 && finishScreenX < canvas.width + 20) {
        ctx.fillStyle = '#fff';
        for (let y = 0; y < canvas.height; y += 20) {
            for (let x = 0; x < 20; x += 10) {
                if ((Math.floor(y / 10) + Math.floor(x / 10)) % 2 === 0) {
                    ctx.fillRect(finishScreenX + x, y, 10, 10);
                }
            }
        }
        ctx.fillStyle = '#f00';
        ctx.font = 'bold 16px monospace';
        ctx.fillText('FINISH', finishScreenX - 20, canvas.height - 10);
    }

    // Draw player
    const playerScreenX = player.x - track.offset;
    ctx.fillStyle = player.color;
    ctx.fillRect(playerScreenX, player.y, player.width, player.height);
    // Car details
    ctx.fillStyle = '#fff';
    ctx.fillRect(playerScreenX + player.width - 5, player.y + 3, 5, 4);
    ctx.fillRect(playerScreenX + player.width - 5, player.y + player.height - 7, 5, 4);
    // Wheels
    ctx.fillStyle = '#333';
    ctx.fillRect(playerScreenX + 2, player.y - 3, 8, 3);
    ctx.fillRect(playerScreenX + 2, player.y + player.height, 8, 3);
    ctx.fillRect(playerScreenX + player.width - 10, player.y - 3, 8, 3);
    ctx.fillRect(playerScreenX + player.width - 10, player.y + player.height, 8, 3);

    // HUD
    ctx.fillStyle = 'rgba(0, 0, 0, 0.7)';
    ctx.fillRect(5, 5, 250, 80);

    ctx.fillStyle = '#fff';
    ctx.font = '14px monospace';
    const elapsed = gameStartTime ? ((performance.now() - gameStartTime) / 1000).toFixed(1) : '0.0';
    ctx.fillText(`Time: ${elapsed}s`, 15, 25);
    ctx.fillText(`Distance: ${Math.floor(player.distanceTraveled)}/${track.finishLine}m`, 15, 45);
    ctx.fillText(`Checkpoints: ${track.checkpointsPassed.length}/${track.checkpoints.length}`, 15, 65);

    // Progress bar
    ctx.fillStyle = '#333';
    ctx.fillRect(5, 90, 250, 15);
    const progress = Math.min(player.distanceTraveled / track.finishLine, 1);
    ctx.fillStyle = '#e94560';
    ctx.fillRect(5, 90, 250 * progress, 15);
    ctx.strokeStyle = '#fff';
    ctx.strokeRect(5, 90, 250, 15);

    // Anti-cheat status
    const status = antiCheat.getStatus();
    ctx.fillStyle = 'rgba(0, 0, 0, 0.7)';
    ctx.fillRect(canvas.width - 260, 5, 255, 60);

    ctx.fillStyle = status.isBanned ? '#f00' : status.anomalies > 3 ? '#ff0' : '#0f0';
    ctx.font = '12px monospace';
    ctx.fillText(`🛡️ Anti-Cheat: ${status.isBanned ? 'BANNED' : status.anomalies > 3 ? 'WARNING' : 'CLEAN'}`, canvas.width - 250, 22);
    ctx.fillStyle = '#aaa';
    ctx.fillText(`Anomalies: ${status.anomalies}/window | Total: ${status.totalViolations}`, canvas.width - 250, 40);
    ctx.fillText(`Max speed: ${antiCheat.maxPlayerSpeed} px/s`, canvas.width - 250, 55);

    // Finish screen
    if (player.finished) {
        ctx.fillStyle = 'rgba(0, 0, 0, 0.8)';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        ctx.fillStyle = '#0f0';
        ctx.font = 'bold 48px monospace';
        ctx.textAlign = 'center';
        ctx.fillText('🏁 RACE COMPLETE! 🏁', canvas.width / 2, canvas.height / 2 - 40);

        ctx.fillStyle = '#fff';
        ctx.font = '24px monospace';
        ctx.fillText(`Time: ${player.finishTime}s`, canvas.width / 2, canvas.height / 2 + 20);
        ctx.fillText(`Violations: ${status.totalViolations}`, canvas.width / 2, canvas.height / 2 + 55);

        ctx.font = '16px monospace';
        ctx.fillStyle = status.totalViolations > 0 ? '#f00' : '#0f0';
        ctx.fillText(
            status.totalViolations > 0 ? '⚠️ Time under review due to anomalies' : '✅ Clean run - time verified!',
            canvas.width / 2, canvas.height / 2 + 90
        );
        ctx.textAlign = 'left';
    }

    // Banned screen
    if (antiCheat.isBanned) {
        ctx.fillStyle = 'rgba(100, 0, 0, 0.9)';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        ctx.fillStyle = '#fff';
        ctx.font = 'bold 36px monospace';
        ctx.textAlign = 'center';
        ctx.fillText('🚫 SPEED HACK DETECTED 🚫', canvas.width / 2, canvas.height / 2 - 30);

        ctx.font = '18px monospace';
        ctx.fillText('Your session has been terminated.', canvas.width / 2, canvas.height / 2 + 20);
        ctx.fillText('Multiple timing anomalies detected.', canvas.width / 2, canvas.height / 2 + 50);

        ctx.font = '14px monospace';
        ctx.fillStyle = '#aaa';
        const recent = status.recentViolations;
        for (let i = 0; i < recent.length; i++) {
            ctx.fillText(
                `${recent[i].type}: ${recent[i].detail}`,
                canvas.width / 2, canvas.height / 2 + 90 + i * 20
            );
        }
        ctx.textAlign = 'left';
    }
}

// Update debug display
function updateDebug() {
    const status = antiCheat.getStatus();
    debugDiv.innerHTML = `
        <span style="color: ${status.isBanned ? '#f00' : '#0f0'}">
            Anti-Cheat Status: ${status.isBanned ? '🚫 BANNED' : '🛡️ Active'}
        </span> |
        Anomalies in window: ${status.anomalies} |
        Total violations: ${status.totalViolations} |
        Frame times tracked: ${antiCheat.frameTimes.length}
    `;
}

// ============================================================
// GAME LOOP using setInterval
// ============================================================

// Use setInterval as required, but anti-cheat validates all timing
const TICK_RATE = 16; // ~60fps target

setInterval(() => {
    update();
    render();
    updateDebug();
}, TICK_RATE);

// ============================================================
// ANTI-TAMPER: Protect critical game variables
// ============================================================

// Freeze the anti-cheat instance to prevent property modification
Object.freeze(antiCheat.constructor.prototype);

// Monitor for console manipulation of player speed
const originalSpeed = player.speed;
setInterval(() => {
    if (player.speed !== originalSpeed && player.speed !== PLAYER_SPEED) {
        antiCheat.recordAnomaly('SPEED_TAMPER', `Speed changed to ${player.speed}`);
        player.speed = PLAYER_SPEED;
    }

    // Detect if setInterval is being manipulated
    // by checking if our monitoring interval runs at expected rate
}, 500);

// Detect if someone tries to override performance.now
const originalPerfNow = performance.now.bind(performance);
setInterval(() => {
    const perf = performance.now();
    const date = Date.now();
    // Simple sanity: both should be moving forward
    if (perf < antiCheat.lastPerformanceNow - 100) {
        antiCheat.recordAnomaly('PERF_TAMPER', 'performance.now went backwards');
    }
}, 1000);

